/// If a loop is unrolled, the trip count of the new loop will be
/// TC / UnrollCount. This function returns the new trip count, taking into
/// account the round-down involved in the division.
static Value *getUnrolledTripCount(ScalarEvolution &SE, const Loop &L,
                                   Value *TripCount, unsigned UnrollCount,
                                   IRBuilder<> &Builder) {
  // The new trip count is floor(TC / UnrollCount).
  // This is the same as TC / UnrollCount in integer division.
  return Builder.CreateUDiv(TripCount, ConstantInt::get(TripCount->getType(),
                                                        UnrollCount));
}

/// Create a new VPlan for an unrolled loop. The new VPlan is stored in \p
/// UnrolledVPlan.
static void
createUnrolledVPlan(VPlan &OrigVPlan, VPlan &UnrolledVPlan,
                    Loop &L, LoopUnrollResult &UnrollResult,
                    DenseMap<Value *, Value *> &SimplifiedValues) {
  ValueToValueMapTy VMap;
  UnrolledVPlan.setEntry(cast<VPBlockBase>(
      VPlan::cloneSubGraph(OrigVPlan.getEntry(), UnrolledVPlan, VMap)));

  // Replace all original values with their simplified values.
  for (auto &KV : SimplifiedValues) {
    auto VPMapped = VMap.find(KV.first);
    if (VPMapped != VMap.end()) {
      auto Simplified = UnrolledVPlan.getOrAddLiveIn(KV.second);
      VPMapped->second->replaceAllUsesWith(Simplified);
    }
  }

  // Replace the trip-count related instructions with the new ones.
  auto *NewTripCount = UnrolledVPlan.getOrAddLiveIn(UnrollResult.NewTripCount);
  auto *OrigTripCount = OrigVPlan.getTripCount();
  VMap[OrigTripCount]->replaceAllUsesWith(NewTripCount);

  auto *NewInduction =
      UnrolledVPlan.getOrAddLiveIn(UnrollResult.NewInduction);
  auto *OrigInduction = OrigVPlan.getInduction();
  VMap[OrigInduction]->replaceAllUsesWith(NewInduction);
}

/// Unroll the given VPlan \p UnrollCount times.
void VPlanTransforms::unroll(VPlan &Plan, unsigned UnrollCount,
                             LoopVectorizationLegality &LVL) {
  // TODO: Support unrolling of loops with VPInstructions.
  if (any_of(Plan.blocks(), [](const VPBlockBase *VPB) {
        return !isa<VPBasicBlock>(VPB) ||
               any_of(VPB->asVPBasicBlock()->recipes(),
                      [](const VPRecipeBase &R) {
                        return isa<VPInstruction>(&R) &&
                               !isa<VPBranchOnMaskRecipe>(&R);
                      });
      }))
    return;

  // Find the loop induction variable and trip count.
  auto *Induction = Plan.getInduction();
  auto *TripCount = Plan.getTripCount();
  if (!Induction || !TripCount)
    return;

  // We need to generate a new trip count for the unrolled loop.
  // The new trip count will be TripCount / UnrollCount.
  // The rest of the loop will be handled by a peel-off loop.
  // TODO: Support peeling.
  Loop &L = LVL.getLoop();
  IRBuilder<> Builder(L.getLoopPreheader()->getTerminator());
  auto *UnrolledTripCount =
      getUnrolledTripCount(*LVL.getSE(), L, TripCount, UnrollCount, Builder);

  // We also need to generate a new induction variable for the unrolled loop.
  // The new induction variable will have a new start value and a new step.
  auto *IV = cast<PHINode>(Induction);
  Value *NewIVStart = IV->getIncomingValueForBlock(L.getLoopPreheader());
  const SCEV *Step = LVL.getSCEV(IV->getIncomingValueForBlock(L.getLoopLatch()))
                         ->getMinusSCEV(LVL.getSCEV(IV));
  const SCEV *NewStep = LVL.getSE()->getMulExpr(
      Step, LVL.getSE()->getConstant(Step->getType(), UnrollCount));

  // Create a new induction variable for the unrolled loop.
  auto *NewIV = Builder.CreatePHI(IV->getType(), 2, "unrolled.iv");
  NewIV->addIncoming(NewIVStart, L.getLoopPreheader());
  Value *NewIVInc =
      Builder.CreateAdd(NewIV, LVL.getSCEV(NewStep)->getExpr(), "unrolled.iv.inc");
  NewIV->addIncoming(NewIVInc, L.getLoopLatch());

  LoopUnrollResult UnrollResult(&L, UnrolledTripCount, NewIV);

  // Simplify the VPlan using the new trip count and induction variable.
  DenseMap<Value *, Value *> SimplifiedValues;
  SimplifiedValues[Induction] = NewIV;
  SimplifiedValues[TripCount] = UnrolledTripCount;

  VPlan UnrolledVPlan;
  createUnrolledVPlan(Plan, UnrolledVPlan, L, UnrollResult, SimplifiedValues);

  // Unroll the VPlan.
  VPBlockBase *Header = UnrolledVPlan.getEntry();
  assert(Header && "No header found");
  VPBlockBase *Latch = Header->getSingleSuccessor();
  assert(Latch && "No latch found");

  VPBlockBase *PrevLatch = Latch;
  for (unsigned I = 1; I < UnrollCount; ++I) {
    ValueToValueMapTy VMap;
    // The induction variable of the I-th unrolled iteration is the induction
    // variable of the previous iteration incremented by Step.
    const SCEV *Inc = LVL.getSE()->getMulExpr(
        Step, LVL.getSE()->getConstant(Step->getType(), I));
    VMap[NewIV] = Builder.CreateAdd(NewIV, LVL.getSCEV(Inc)->getExpr());

    // The trip count does not change between unrolled iterations.
    VMap[NewTripCount] = NewTripCount;

    // Clone the body of the loop.
    VPBlockBase *NewHeader =
        cast<VPBlockBase>(VPlan::cloneSubGraph(Header, UnrolledVPlan, VMap));
    VPBlockBase *NewLatch = NewHeader->getSingleSuccessor();

    // Connect the previous latch to the new header.
    PrevLatch->setSuccessor(0, NewHeader);
    NewHeader->setPredecessor(0, PrevLatch);
    PrevLatch = NewLatch;
  }

  // Connect the last latch to the original header.
  PrevLatch->setSuccessor(0, Header);
  Header->setPredecessor(0, PrevLatch);

  // Replace the original VPlan with the unrolled one.
  Plan = std::move(UnrolledVPlan);
}

/// Replicate the given VPlan \p VF.getKnownMinValue() times. This is used to fully unroll a
/// VPlan, when the trip count is known.
void VPlanTransforms::replicate(VPlan &Plan, ElementCount VF) {
  assert(VF.isScalar() && "VF must be a scalar");
  VPBlockBase *Header = Plan.getEntry();
  assert(Header && "No header found");
  VPBlockBase *Latch = Header->getSingleSuccessor();
  assert(Latch && "No latch found");

  VPBlockBase *PrevLatch = Latch;
  for (unsigned I = 1; I < VF.getKnownMinValue(); ++I) {
    ValueToValueMapTy VMap;
    // The trip count does not change between unrolled iterations.
    VMap[Plan.getTripCount()] = Plan.getTripCount();

    // Clone the body of the loop.
    VPBlockBase *NewHeader =
        cast<VPBlockBase>(VPlan::cloneSubGraph(Header, Plan, VMap));
    VPBlockBase *NewLatch = NewHeader->getSingleSuccessor();

    // Connect the previous latch to the new header.
    PrevLatch->setSuccessor(0, NewHeader);
    NewHeader->setPredecessor(0, PrevLatch);
    PrevLatch = NewLatch;
  }

  // Connect the last latch to the original header.
  PrevLatch->setSuccessor(0, Header);
  Header->setPredecessor(0, PrevLatch);
}

/// A helper class to clone recipes for whole-vector replication.
class VPReplicator {
  VPlan &Plan;
  VPBuilder &Builder;
  Type *IdxTy;
  DenseMap<VPRecipeBase *, SmallVector<VPValue *, 1>> &Def2LaneDefs;

public:
  VPReplicator(
      VPlan &Plan, VPBuilder &Builder, Type *IdxTy,
      DenseMap<VPRecipeBase *, SmallVector<VPValue *, 1>> &Def2LaneDefs)
      : Plan(Plan), Builder(Builder), IdxTy(IdxTy), Def2LaneDefs(Def2LaneDefs) {
  }

  /// A helper function to clone the given recipe \p RepR for a given lane \p
  /// Lane.
  VPValue *cloneForLane(VPRecipeBase *RepR, VPLane Lane);

private:
  /// A helper function to get the lane-specific value for a given operand \p
  /// Op of a recipe to be cloned for lane \p Lane.
  VPValue *getLaneIn(VPValue *Op, VPLane Lane);
};

VPValue *VPReplicator::getLaneIn(VPValue *Op, VPLane Lane) {
  if (Op->isLiveIn())
    return Op;

  VPRecipeBase *Def = Op->getDef();
  auto It = Def2LaneDefs.find(Def);
  if (It != Def2LaneDefs.end()) {
    // The definition has already been replicated. Return the lane-specific
    // value.
    return It->second[Lane.getAsRuntimeExpr(Builder)];
  }

  // The definition has not been replicated yet. Replicate it now.
  return cloneForLane(Def, Lane);
}

VPValue *VPReplicator::cloneForLane(VPRecipeBase *RepR, VPLane Lane) {
  assert(!Def2LaneDefs.count(RepR) && "Recipe must be replicated before its uses");
  SmallVector<VPValue *, 1> &LaneDefs = Def2LaneDefs[RepR];
  assert(LaneDefs.empty() && "Recipe has already been replicated");

  // Replicate the recipe for each lane.
  for (unsigned I = 0, E = Lane.getVF().getKnownMinValue(); I != E; ++I) {
    VPLane SubLane = VPLane(I, Lane.getVF());
    SmallVector<VPValue *, 4> In;
    for (VPValue *Op : RepR->operands())
      In.push_back(getLaneIn(Op, SubLane));

    VPRecipeBase *NewR = RepR->clone();
    for (unsigned J = 0, E = In.size(); J != E; ++J)
      NewR->setOperand(J, In[J]);

    Builder.insert(NewR);
    assert(NewR->getNumDefinedValues() == 1 &&
           "Can only replicate single-def recipes");
    LaneDefs.push_back(NewR->getVPSingleValue());
  }

  // Return the value for the requested lane.
  return LaneDefs[Lane.getAsRuntimeExpr(Builder)];
}

